use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::todo_title::TodoTitle;
use super::user::UserId;

#[derive(Debug, Clone, PartialEq)]
pub struct InboxItemId(Uuid);

impl Default for InboxItemId {
    fn default() -> Self {
        Self::new()
    }
}

impl InboxItemId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

#[derive(Debug, Clone)]
pub struct InboxItem {
    id: InboxItemId,
    user_id: UserId,
    title: TodoTitle,
    created_at: DateTime<Utc>,
}

impl InboxItem {
    pub fn new(user_id: UserId, title: TodoTitle) -> Self {
        Self {
            id: InboxItemId::new(),
            user_id,
            title,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: InboxItemId,
        user_id: UserId,
        title: TodoTitle,
        created_at: DateTime<Utc>,
    ) -> Self {
        Self {
            id,
            user_id,
            title,
            created_at,
        }
    }

    pub fn id(&self) -> &InboxItemId {
        &self.id
    }

    pub fn user_id(&self) -> &UserId {
        &self.user_id
    }

    pub fn title(&self) -> &TodoTitle {
        &self.title
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        &self.created_at
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn new_inbox_item_has_title_and_user() {
        let user_id = UserId::new();
        let title = TodoTitle::parse("Buy groceries".to_string()).unwrap();
        let item = InboxItem::new(user_id.clone(), title);

        assert_eq!(item.title().as_str(), "Buy groceries");
        assert_eq!(item.user_id(), &user_id);
    }

    #[test]
    fn inbox_item_id_is_unique() {
        let id1 = InboxItemId::new();
        let id2 = InboxItemId::new();
        assert_ne!(id1, id2);
    }

    #[test]
    fn inbox_item_from_parts_preserves_fields() {
        let id = InboxItemId::new();
        let user_id = UserId::new();
        let title = TodoTitle::parse("Test".to_string()).unwrap();
        let now = Utc::now();

        let item = InboxItem::from_parts(id.clone(), user_id.clone(), title, now);

        assert_eq!(item.id(), &id);
        assert_eq!(item.user_id(), &user_id);
        assert_eq!(item.title().as_str(), "Test");
        assert_eq!(item.created_at(), &now);
    }
}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{InboxItem, InboxItemId, TodoTitle, UserId};

struct InboxRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
}

impl InboxRecord {
    fn into_domain(self) -> InboxItem {
        let id = InboxItemId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        InboxItem::from_parts(id, user_id, title, self.created_at)
    }
}

pub async fn insert_inbox_item(pool: &PgPool, item: &InboxItem) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO inbox_items (id, user_id, title, created_at)
           VALUES ($1, $2, $3, $4 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        item.created_at() as &DateTime<Utc>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_inbox_items_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<InboxItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        InboxRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM inbox_items WHERE user_id = $1 ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: InboxRecord| r.into_domain())
        .collect())
}

pub async fn count_inbox_items(pool: &PgPool, user_id: &UserId) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM inbox_items WHERE user_id = $1"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn delete_inbox_item(pool: &PgPool, item_id: &InboxItemId) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_inbox_item_by_id(
    pool: &PgPool,
    item_id: &InboxItemId,
) -> Result<Option<InboxItem>, sqlx::Error> {
    let record: Option<InboxRecord> = sqlx::query_as!(
        InboxRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r: InboxRecord| r.into_domain()))
}

use sqlx::PgPool;

use crate::domain::{InboxItem, InboxItemId, TodoTitle, TodoTitleError, UserId};
use crate::infrastructure::inbox_repository;

#[derive(Debug, thiserror::Error)]
pub enum CaptureInboxError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "capture_inbox_item",
    skip(pool, title),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn capture_inbox_item(
    pool: &PgPool,
    user_id: UserId,
    title: String,
) -> Result<InboxItem, CaptureInboxError> {
    let title = TodoTitle::parse(title)?;
    let item = InboxItem::new(user_id, title);

    inbox_repository::insert_inbox_item(pool, &item)
        .await
        .map_err(|e| {
            CaptureInboxError::Unexpected(anyhow::anyhow!("Failed to insert inbox item: {e}"))
        })?;

    tracing::info!("Inbox item captured");
    Ok(item)
}

#[tracing::instrument(
    name = "get_inbox_items",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn get_inbox_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<InboxItem>, anyhow::Error> {
    let items = inbox_repository::find_inbox_items_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch inbox items: {e}"))?;

    Ok(items)
}

#[tracing::instrument(
    name = "get_inbox_count",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn get_inbox_count(pool: &PgPool, user_id: &UserId) -> Result<i64, anyhow::Error> {
    let count = inbox_repository::count_inbox_items(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count inbox items: {e}"))?;

    Ok(count)
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteInboxError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to delete this inbox item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_inbox_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_inbox_item(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
) -> Result<(), DeleteInboxError> {
    let item = inbox_repository::find_inbox_item_by_id(pool, item_id)
        .await
        .map_err(|e| DeleteInboxError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteInboxError::NotFound)?;

    if item.user_id() != user_id {
        return Err(DeleteInboxError::Unauthorized);
    }

    inbox_repository::delete_inbox_item(pool, item_id)
        .await
        .map_err(|e| {
            DeleteInboxError::Unexpected(anyhow::anyhow!("Failed to delete inbox item: {e}"))
        })?;

    tracing::info!("Inbox item deleted");
    Ok(())
}

