{% extends "base.html" %}

{% block title %}Inbox -- Todo List{% endblock %}

{% block nav %}
{% include "gtd_nav.html" %}
{% endblock %}

{% block content %}
<div class="inbox">
    <h1>Inbox</h1>

    <form
        method="post"
        action="/inbox"
        class="inbox-capture"
        hx-post="/inbox"
        hx-target="#inbox-list"
        hx-swap="beforeend"
        hx-on::after-request="if(event.detail.successful) this.reset(); this.querySelector('#inbox-title').focus();"
    >
        <label for="inbox-title">Capture</label>
        <input
            type="text"
            id="inbox-title"
            name="title"
            placeholder="What's on your mind?"
            maxlength="300"
            autocomplete="off"
            class="inbox-capture__input"
        >
        <button type="submit" class="inbox-capture__submit">Capture</button>
    </form>

    {% if items.is_empty() %}
    <div class="inbox__empty-state" id="inbox-empty-state">
        <p>Inbox zero -- nothing to process. <a href="#inbox-title">Capture something new</a> or start your <a href="/review">weekly review</a>.</p>
    </div>
    {% endif %}
    <ul class="inbox__list" role="list" id="inbox-list"{% if items.is_empty() %} hidden{% endif %}>
        {% for item in items %}
        {% include "inbox_item.html" %}
        {% endfor %}
    </ul>
</div>
{% endblock %}

{% block scripts %}
<script>
// Hide empty state and show list when items are added via HTMX
document.getElementById('inbox-list').addEventListener('htmx:afterSwap', function() {
    var list = document.getElementById('inbox-list');
    var emptyState = document.getElementById('inbox-empty-state');
    if (list && list.children.length > 0) {
        list.hidden = false;
        if (emptyState) emptyState.hidden = true;
    }
});
// Show empty state when list becomes empty after HTMX delete
document.body.addEventListener('htmx:afterSettle', function() {
    var list = document.getElementById('inbox-list');
    var emptyState = document.getElementById('inbox-empty-state');
    if (list && list.children.length === 0 && emptyState) {
        list.hidden = true;
        emptyState.hidden = false;
    }
});
</script>
{% endblock %}

use askama::Template;
use axum::extract::State;
use axum::http::StatusCode;
use axum::response::{Html, IntoResponse, Response};
use sqlx::PgPool;

use super::auth::AuthenticatedUser;
use crate::services::inbox_service;

#[derive(Template)]
#[template(path = "gtd_placeholder.html")]
struct GtdPlaceholderTemplate {
    current_page: &'static str,
    page_title: &'static str,
    heading: &'static str,
    description: &'static str,
    inbox_count: i64,
}

#[derive(Debug, thiserror::Error)]
pub enum GtdPlaceholderError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

impl IntoResponse for GtdPlaceholderError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "GTD placeholder error");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

async fn render_placeholder(
    user_id: &crate::domain::UserId,
    pool: &PgPool,
    current_page: &'static str,
    page_title: &'static str,
    heading: &'static str,
    description: &'static str,
) -> Result<impl IntoResponse, GtdPlaceholderError> {
    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
        .await
        .map_err(GtdPlaceholderError::Unexpected)?;

    let template = GtdPlaceholderTemplate {
        current_page,
        page_title,
        heading,
        description,
        inbox_count,
    };
    Ok(Html(template.render()?))
}

pub async fn get_next_actions(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
) -> Result<impl IntoResponse, GtdPlaceholderError> {
    render_placeholder(
        &user_id,
        &pool,
        "next_actions",
        "Next Actions -- Todo List",
        "Next Actions",
        "Concrete actions you can do right now, organized by context.",
    )
    .await
}

