1198→  }
1199→
1200→  .inbox-item__title {
1201→    flex: 1;
1202→    min-inline-size: 0;
1203→    overflow-wrap: break-word;
1204→  }
1205→
1206→  .inbox-item__delete {
1207→    flex-shrink: 0;
1208→  }
1209→
1210→  .inbox-item__delete-button {
1211→    background: none;
1212→    border: none;
1213→    padding: var(--space-xs);
1214→    cursor: pointer;
1215→    color: var(--color-fg-muted);
1216→    font-size: var(--font-size-sm);
